        nextLabel: "\u041D\u0430\u0432\u044B\u043A \u043F\u043E\u043B\u0443\u0447\u0435\u043D. \u0414\u0430\u043B\u044C\u0448\u0435 \u2014 \u0443\u0437\u043D\u0430\u0435\u043C, \u043A\u0430\u043A \u044D\u0442\u0438 \u043B\u0438\u043D\u0438\u0438 \u043D\u0430\u0437\u044B\u0432\u0430\u044E\u0442\u0441\u044F."
