        node: "\u0417\u0430\u043A\u043E\u043D 4 \xB7 \u0418\u0437\u043E\u043C\u043E\u0440\u0444\u0438\u044F",
        title: "\u0423\u0442\u0440\u043E = \u0412\u0435\u0441\u043D\u0430. \u0414\u0435\u043D\u044C = \u041B\u0435\u0442\u043E",
        subtitle: "\u0421\u0443\u0442\u043A\u0438 \u0438 \u0413\u043E\u0434 \u0438\u043C\u0435\u044E\u0442 \u043E\u0434\u0438\u043D\u0430\u043A\u043E\u0432\u043E\u0435 \u0443\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E",
        stages: [
          { at: 0, hl: [3], af: ["support"], note: "\u041F\u043E\u043B\u043A\u0430 3 = \u0423\u0442\u0440\u043E (\u0421\u0443\u0442\u043A\u0438) = \u0412\u0435\u0441\u043D\u0430 (\u0413\u043E\u0434)" },
          { at: 3500, hl: [3, 6], af: ["support"], note: "\u041F\u043E\u043B\u043A\u0430 6 = \u0414\u0435\u043D\u044C (\u0421\u0443\u0442\u043A\u0438) = \u041B\u0435\u0442\u043E (\u0413\u043E\u0434)" },
          { at: 7e3, hl: [3, 6, 9], af: ["support"], note: "\u041F\u043E\u043B\u043A\u0430 9 = \u0412\u0435\u0447\u0435\u0440 (\u0421\u0443\u0442\u043A\u0438) = \u041E\u0441\u0435\u043D\u044C (\u0413\u043E\u0434)" },
          { at: 10500, hl: [0, 3, 6, 9], af: ["support"], note: "\u041F\u043E\u043B\u043A\u0430 0 = \u041D\u043E\u0447\u044C (\u0421\u0443\u0442\u043A\u0438) = \u0417\u0438\u043C\u0430 (\u0413\u043E\u0434)" }
        ],
        narrative: [
          { stageIdx: 0, text: "\u0421\u0430\u043C\u043E\u0435 \u0432\u0430\u0436\u043D\u043E\u0435 \u043E\u0442\u043A\u0440\u044B\u0442\u0438\u0435 \u043F\u0435\u0440\u0432\u043E\u0439 \u0447\u0430\u0441\u0442\u0438 \u043A\u043D\u0438\u0433\u0438: \u0413\u043E\u0434 \u0443\u0441\u0442\u0440\u043E\u0435\u043D \u0422\u041E\u0427\u041D\u041E \u043A\u0430\u043A \u0421\u0443\u0442\u043A\u0438. \u042D\u0442\u043E \u043D\u0435 \u043C\u0435\u0442\u0430\u0444\u043E\u0440\u0430, \u0430 \u0444\u043E\u0440\u043C\u0430\u043B\u044C\u043D\u0430\u044F \u0438\u0437\u043E\u043C\u043E\u0440\u0444\u0438\u044F \u2014 \u043A\u0430\u0436\u0434\u043E\u0439 \u041F\u043E\u043B\u043A\u0435 \u0421\u0443\u0442\u043E\u043A \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u041F\u043E\u043B\u043A\u0430 \u0413\u043E\u0434\u0430." },
          { stageIdx: 1, text: "\u041E\u0442 \u0417\u0438\u043C\u043D\u0435\u0433\u043E \u0421\u043E\u043B\u043D\u0446\u0435\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0434\u043E \u041B\u0435\u0442\u043D\u0435\u0433\u043E \u0434\u0435\u043D\u044C \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0443\u0434\u043B\u0438\u043D\u044F\u0435\u0442\u0441\u044F. \u042D\u0442\u043E \u2014 \u0412\u0435\u0441\u043D\u0430. \u0418 \u044D\u0442\u043E \u2014 \u0423\u0442\u0440\u043E \u0413\u043E\u0434\u0430. \u0423\u0442\u0440\u043E = \u0412\u0435\u0441\u043D\u0430." },
          { stageIdx: 2, text: "\u041E\u0442 \u0412\u0435\u0441\u0435\u043D\u043D\u0435\u0433\u043E \u0420\u0430\u0432\u043D\u043E\u0434\u0435\u043D\u0441\u0442\u0432\u0438\u044F \u0434\u043E \u041E\u0441\u0435\u043D\u043D\u0435\u0433\u043E \u0421\u043E\u043B\u043D\u0446\u0435 \u043D\u0430\u0434 \u041F\u043B\u043E\u0441\u043A\u043E\u0441\u0442\u044C\u044E \u042D\u043A\u0432\u0430\u0442\u043E\u0440\u0430. \u042D\u0442\u043E \u2014 \u041B\u0435\u0442\u043E. \u0418 \u044D\u0442\u043E \u2014 \u0414\u0435\u043D\u044C \u0413\u043E\u0434\u0430. \u0414\u0435\u043D\u044C = \u041B\u0435\u0442\u043E." },
          { stageIdx: 3, text: "\u041E\u0442 \u041B\u0435\u0442\u043D\u0435\u0433\u043E \u0421\u043E\u043B\u043D\u0446\u0435\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0434\u043E \u0417\u0438\u043C\u043D\u0435\u0433\u043E \u0434\u0435\u043D\u044C \u0443\u043A\u043E\u0440\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F. \u042D\u0442\u043E \u2014 \u041E\u0441\u0435\u043D\u044C. \u0412\u0435\u0447\u0435\u0440 \u0413\u043E\u0434\u0430. \u0412\u0435\u0447\u0435\u0440 = \u041E\u0441\u0435\u043D\u044C." },
          { stageIdx: 3, offset: 4e3, text: "\u0418 \u043E\u0442 \u041E\u0441\u0435\u043D\u043D\u0435\u0433\u043E \u0420\u0430\u0432\u043D\u043E\u0434\u0435\u043D\u0441\u0442\u0432\u0438\u044F \u0434\u043E \u0412\u0435\u0441\u0435\u043D\u043D\u0435\u0433\u043E \u0421\u043E\u043B\u043D\u0446\u0435 \u043F\u043E\u0434 \u042D\u043A\u0432\u0430\u0442\u043E\u0440\u043E\u043C. \u0417\u0438\u043C\u0430. \u041D\u043E\u0447\u044C \u0413\u043E\u0434\u0430. \u041D\u043E\u0447\u044C = \u0417\u0438\u043C\u0430.", kind: "key" },
          { stageIdx: 3, offset: 8500, text: "\u042D\u0442\u0430 \u0438\u0437\u043E\u043C\u043E\u0440\u0444\u0438\u044F \u2014 \u0433\u043B\u0430\u0432\u043D\u043E\u0435 \xAB\u0437\u0435\u0440\u043D\u043E \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F\xBB \u0413\u043E\u0434\u0430. \u0422\u043E\u0442 \u0436\u0435 \u0437\u0430\u043A\u043E\u043D \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0432 \u0434\u0432\u0443\u0445 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0445 \u0440\u0430\u0437\u043C\u0435\u0440\u0430\u0445 \u2014 \u0441\u0443\u0442\u043E\u0447\u043D\u043E\u043C \u0438 \u0433\u043E\u0434\u043E\u0432\u043E\u043C.", kind: "mnemonic" },
          { stageIdx: 3, offset: 13500, text: "\u0410 \u0432 \u0416\u0438\u0437\u043D\u0438 \u2014 \u0432 \u0442\u0440\u0435\u0442\u044C\u0435\u043C \u043C\u0430\u0441\u0448\u0442\u0430\u0431\u0435. \u0422\u0430 \u0436\u0435 \u0434\u0432\u0435\u043D\u0430\u0434\u0446\u0430\u0442\u0435\u0440\u0438\u0447\u043D\u0430\u044F \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0430 \u043E\u0442 \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0434\u043E \u043F\u0430\u043C\u044F\u0442\u043D\u0438\u043A\u0430.", kind: "bridge" }
        ],
        totalDuration: 22e3
