          { stageIdx: 5, offset: 4500, text: "\u0417\u0434\u0435\u0441\u044C \u043D\u0435\u0442 \u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u0430\u043D\u0438\u0439. \u0422\u043E\u043B\u044C\u043A\u043E \u0440\u0430\u0437\u043C\u0435\u0442\u043A\u0430 \u0432\u0440\u0435\u043C\u0435\u043D\u0438. \u0417\u043E\u0434\u0438\u0430\u043A \u2014 \u0434\u0440\u0435\u0432\u043D\u0438\u0439 \u043A\u0430\u043B\u0435\u043D\u0434\u0430\u0440\u044C, \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442 \u0434\u043B\u044F \u0440\u0430\u0437\u0433\u043E\u0432\u043E\u0440\u0430 \u043E \u0444\u0430\u0437\u0430\u0445 \u0413\u043E\u0434\u0430.", kind: "caveat" }
