          { stageIdx: 1, text: "\u041F\u043E\u043B\u043A\u0430 3 \u2014 \u041E\u0432\u0435\u043D, \u042D\u043A\u0432\u0430\u0442\u043E\u0440, \u041C\u043E\u043D\u0435\u0442\u043D\u044B\u0439 \u0414\u0432\u043E\u0440, \u0421\u0442\u0438\u0445\u0438\u044F \u041E\u0433\u043D\u044F, \u0416\u0430\u0440\u043A\u043E. \u042D\u0442\u043E \u043F\u043E\u043B\u044E\u0441 \u043D\u0430\u0447\u0430\u043B\u0430, \u043F\u0435\u0447\u0430\u0442\u044C \u043D\u043E\u0432\u044B\u0445 \u0434\u0435\u043D\u0435\u0433." },
          { stageIdx: 2, text: "\u041C\u0435\u0436\u0434\u0443 \u043D\u0438\u043C\u0438 \u2014 \u041B\u0438\u043D\u0438\u044F \u0411\u043E\u0440\u044C\u0431\u044B. \u0412\u043E\u0439\u043D\u0430 \u0438 \u041C\u0438\u0440. \u0418\u0435\u0440\u0443\u0445 \u0438 \u0421\u0430\u043B\u0438\u043C. \u041E\u0433\u043E\u043D\u044C \u0438 \u0412\u043E\u0434\u0430. \u041E\u0432\u0435\u043D \u0438 \u0412\u0435\u0441\u044B.", kind: "key" },
          { stageIdx: 2, offset: 4500, text: "\u0415\u0441\u043B\u0438 \u0437\u0430\u043F\u043E\u043C\u043D\u0438\u0442\u044C \u0442\u043E\u043B\u044C\u043A\u043E \u043E\u0434\u043D\u043E \u0438\u0437 \u0432\u0441\u0435\u0439 \u043A\u043D\u0438\u0433\u0438 \u2014 \u0437\u0430\u043F\u043E\u043C\u043D\u0438 \u044D\u0442\u0443 \u043E\u0441\u044C. \u0414\u0435\u0432\u044F\u0442\u043A\u0430 \u043F\u0440\u043E\u0442\u0438\u0432 \u0442\u0440\u043E\u0439\u043A\u0438. \u041E\u0441\u0435\u043D\u044C \u043F\u0440\u043E\u0442\u0438\u0432 \u0412\u0435\u0441\u043D\u044B. \u0423\u0440\u043E\u0436\u0430\u0439 \u043F\u0440\u043E\u0442\u0438\u0432 \u0417\u0430\u0447\u0430\u0442\u0438\u044F.", kind: "mnemonic" },
          { stageIdx: 2, offset: 9500, text: "\u042D\u0442\u043E \u0444\u0438\u043D\u0430\u043B\u044C\u043D\u0430\u044F \u0441\u0432\u043E\u0434\u043A\u0430 \u042F\u0441\u043D\u044B \u0413\u043E\u0434\u0430. \u0414\u0430\u043B\u044C\u0448\u0435 \u2014 \u042F\u0441\u043D\u0430 \u0416\u0438\u0437\u043D\u0438, \u0433\u0434\u0435 \u0442\u0430 \u0436\u0435 \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0430 \u0440\u0430\u0437\u0432\u0435\u0440\u043D\u0451\u0442\u0441\u044F \u0432 \u0442\u0440\u0435\u0442\u044C\u0435\u043C, \u0441\u0430\u043C\u043E\u043C \u0431\u043E\u043B\u044C\u0448\u043E\u043C \u043C\u0430\u0441\u0448\u0442\u0430\u0431\u0435.", kind: "bridge" }
